+    local procedure UpdateServiceHeaderStatus()
+    begin
+        UpdateServiceHeaderStatusWithOptions(false);
+    end;
+
+    local procedure UpdateServiceHeaderStatusWithOptions(Deleting: Boolean)
+    var
+        ServItemLine2: Record "Service Item Line";
+        ServHeader2: Record "Service Header";
+        ServHeader3: Record "Service Header";
+        RepairStatus3: Record "Repair Status";
+        RepairStatus4: Record "Repair Status";
+        RepairStatusPriority2: Option;
+        UseLineNo2: Integer;
+        FoundLine: Boolean;
+    begin
+        FoundLine := false;
+        
+        if not Deleting then begin
+            if "Repair Status Code" = '' then
+                exit;
+            RepairStatus3.Get("Repair Status Code");
+            RepairStatusPriority2 := RepairStatus3.Priority;
+            UseLineNo2 := "Line No.";
+            FoundLine := true;
+        end;
+
+        ServItemLine2.Reset();
+        ServItemLine2.SetRange("Document Type", "Document Type");
+        ServItemLine2.SetRange("Document No.", "Document No.");
+        ServItemLine2.SetFilter("Line No.", '<>%1', "Line No.");
+        ServItemLine2.SetFilter("Repair Status Code", '<>%1', '');
+        if ServItemLine2.Find('-') then
+            repeat
+                RepairStatus4.Get(ServItemLine2."Repair Status Code");
+                if not FoundLine then begin
+                    RepairStatusPriority2 := RepairStatus4.Priority;
+                    UseLineNo2 := ServItemLine2."Line No.";
+                    FoundLine := true;
+                end else
+                    if RepairStatus4.Priority < RepairStatusPriority2 then begin
+                        RepairStatusPriority2 := RepairStatus4.Priority;
+                        UseLineNo2 := ServItemLine2."Line No.";
+                    end;
+            until ServItemLine2.Next() = 0;
+
+        if not FoundLine then
+            exit;
+
+        if "Line No." <> UseLineNo2 then begin
+            ServItemLine2.Get("Document Type", "Document No.", UseLineNo2);
+            RepairStatus3.Get(ServItemLine2."Repair Status Code");
+        end else
+            RepairStatus3.Get("Repair Status Code");
+
+        ServHeader2.Get("Document Type", "Document No.");
+        ServHeader3 := ServHeader2;
+        if ServHeader2.Status <> RepairStatus3."Service Order Status" then begin
+            ServHeader2.SetValidatingFromLines(true);
+            ServHeader2.Validate(Status, RepairStatus3."Service Order Status");
+            if not (ServHeader2.Status = ServHeader2.Status::Finished) then begin
+                ServHeader2."Finishing Date" := 0D;
+                ServHeader2."Finishing Time" := 0T;
+                ServHeader2."Service Time (Hours)" := 0;
+            end;
+            ServHeader2.UpdateServiceOrderChangeLog(ServHeader3);
+            ServHeader2.Modify();
+        end;
+    end;
